#include<iostream>#include<vector>#include<algorithm>#include<climits>using namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int> a(n);        int max=INT_MIN;        int index=-1;        for(int i=0;i<n;i++){            cin>>a[i];            if(a[i]>max){                max=a[i];                index=i;            }        }        if(index==0){            for(int i=0;i<n;i++){                cout<<a[i]<<" ";            }            cout<<"\n";        }        else{            swap(a[0],a[index]);            for(int i=0;i<n;i++){                cout<<a[i]<<" ";            }            cout<<"\n";        }    }}